import React, { useState, useEffect } from 'react';
import { useSearchParams } from 'react-router-dom';
import Layout from '../components/shared/Layout';
import { PlatformIcons, PLATFORMS } from '../utils/platforms';
import { integrationsAPI } from '../utils/api';
import api from '../utils/api';

const SERVER_URL = process.env.REACT_APP_API_URL || 'http://localhost:5000';

const PLATFORM_FIELDS = {
  meta: {
    label: 'Meta (Facebook & Instagram Ads)',
    oauthSupported: true,
    oauthLabel: 'Connect with Facebook',
    oauthColor: '#1877F2',
    oauthIcon: '🔵',
    instructions: [
      { step:1, text:'Click "Connect with Facebook" below for automatic setup — no manual token needed.' },
      { step:2, text:'Log in with your Facebook account and approve the requested permissions.' },
      { step:3, text:'AdsPulse will automatically get a 60-day token and link your ad account.' },
      { step:4, text:'For a never-expiring token, use a System User token from Meta Business Manager instead.' },
    ],
    fields: [
      { key:'accessToken', label:'Access Token (manual alternative)', type:'password', placeholder:'EAAxxxxxxxxxx...' },
      { key:'adAccountId', label:'Ad Account ID', placeholder:'act_123456789' },
    ],
    docs: 'https://developers.facebook.com/docs/marketing-api/get-started',
    tip: 'OAuth login is recommended. Manual token expires in 60 days unless you use a System User token.'
  },
  google: {
    label: 'Google Ads',
    oauthSupported: false,
    instructions: [
      { step:1, text:'Go to Google Ads → Tools & Settings → API Center to get your Developer Token' },
      { step:2, text:'Create OAuth2 credentials in Google Cloud Console → APIs & Services → Credentials' },
      { step:3, text:'Your Customer ID is the 10-digit number in the top-right of Google Ads (e.g. 123-456-7890)' },
      { step:4, text:'Use OAuth2 Playground (developers.google.com/oauthplayground) to generate tokens' },
    ],
    fields: [
      { key:'developerToken', label:'Developer Token', type:'password', placeholder:'xxxxxxxxxxxx', required:true },
      { key:'customerId',     label:'Customer ID',     placeholder:'123-456-7890',                  required:true },
      { key:'accessToken',    label:'Access Token',    type:'password', placeholder:'ya29.xxxx',    required:true },
      { key:'refreshToken',   label:'Refresh Token',   type:'password', placeholder:'1//xxxx' },
    ],
    docs: 'https://developers.google.com/google-ads/api/docs/get-started/introduction',
    tip: 'Make sure Google Ads API is enabled in your Google Cloud project.'
  },
  tiktok: {
    label: 'TikTok For Business',
    oauthSupported: false,
    instructions: [
      { step:1, text:'Go to TikTok for Business → Apps (business-api.tiktok.com) → Create App' },
      { step:2, text:'In your app settings → Authorization → generate an Access Token' },
      { step:3, text:'Your Advertiser ID is in TikTok Ads Manager Account Settings' },
    ],
    fields: [
      { key:'accessToken',  label:'Access Token',      type:'password', placeholder:'xxxxxxxxxxxxxxxx', required:true },
      { key:'advertiserId', label:'Advertiser ID',     placeholder:'7000000000000000000',               required:true },
      { key:'appId',        label:'App ID (optional)', placeholder:'xxxxxxxxxxxxxxxx' },
    ],
    docs: 'https://business-api.tiktok.com/portal/docs',
    tip: 'Required scope: campaign:read, adgroup:read, ad:read, report:read'
  },
  linkedin: {
    label: 'LinkedIn Campaign Manager',
    oauthSupported: true,
    oauthLabel: 'Connect with LinkedIn',
    oauthColor: '#0A66C2',
    oauthIcon: '🔷',
    instructions: [
      { step:1, text:'Click "Connect with LinkedIn" for automatic setup — no manual token needed.' },
      { step:2, text:'Log in with your LinkedIn account and approve the permissions.' },
      { step:3, text:'Requires Marketing Developer Platform access (apply in your LinkedIn app).' },
      { step:4, text:'Token is valid for 60 days and auto-refreshes when you reconnect.' },
    ],
    fields: [
      { key:'accessToken', label:'Access Token (manual alternative)', type:'password', placeholder:'AQxxxxxx' },
      { key:'adAccountId', label:'Ad Account ID',                     placeholder:'123456789' },
    ],
    docs: 'https://learn.microsoft.com/en-us/linkedin/marketing/',
    tip: 'LinkedIn Marketing API requires approval. Apply at linkedin.com/developers.'
  },
  twitter: {
    label: 'X (Twitter) Ads',
    oauthSupported: false,
    instructions: [
      { step:1, text:'Apply at developer.twitter.com → Create Project → Get Elevated Access' },
      { step:2, text:'Generate a Bearer Token from the Keys & Tokens tab' },
    ],
    fields: [
      { key:'bearerToken', label:'Bearer Token', type:'password', placeholder:'AAAAAAAAAAAAAAAAAAAAAxx...', required:true },
      { key:'apiKey',      label:'API Key (optional)',    placeholder:'xxxxxxxxxxxxxxxxxxxx' },
      { key:'apiSecret',   label:'API Secret (optional)', type:'password', placeholder:'xxxxxxxxxxxxxxxxxxxx' },
    ],
    docs: 'https://developer.twitter.com/en/docs/twitter-ads-api',
    tip: 'The Ads API requires separate approval from standard Twitter Developer access.'
  },
  snapchat: {
    label: 'Snapchat Ads',
    oauthSupported: false,
    instructions: [
      { step:1, text:'Apply at snap.com/en-US/advertise → contact Snapchat for Business API access' },
      { step:2, text:'Create an app at developers.snap.com → generate Access Token via OAuth2' },
    ],
    fields: [
      { key:'accessToken', label:'Access Token',  type:'password', placeholder:'xxxxxxxx-xxxx-xxxx-xxxx-xxxxxxxxxxxx', required:true },
      { key:'adAccountId', label:'Ad Account ID', placeholder:'xxxxxxxx-xxxx-xxxx-xxxx-xxxxxxxxxxxx',                 required:true },
    ],
    docs: 'https://marketingapi.snapchat.com/docs/',
    tip: 'Snapchat Marketing API access requires approval from your Snapchat account manager.'
  },
  youtube: {
    label: 'YouTube (via Google OAuth)',
    oauthSupported: false,
    instructions: [
      { step:1, text:'Enable "YouTube Data API v3" in Google Cloud Console' },
      { step:2, text:'Use OAuth2 Playground to get an Access Token with youtube.readonly scope' },
    ],
    fields: [
      { key:'accessToken',  label:'Access Token',   type:'password', placeholder:'ya29.xxxx', required:true },
      { key:'refreshToken', label:'Refresh Token',  type:'password', placeholder:'1//xxxx' },
      { key:'clientId',     label:'Client ID',      placeholder:'xxxx.apps.googleusercontent.com' },
    ],
    docs: 'https://developers.google.com/youtube/v3/getting-started',
    tip: 'Required scope: https://www.googleapis.com/auth/youtube.readonly'
  },
};

export default function ConnectPage() {
  const [searchParams, setSearchParams] = useSearchParams();
  const [connections, setConnections]   = useState({});
  const [connecting, setConnecting]     = useState(null);
  const [credentials, setCredentials]   = useState({});
  const [syncing, setSyncing]           = useState(null);
  const [checkingPerms, setCheckingPerms] = useState(null);
  const [permResults, setPermResults]   = useState({});
  const [saving, setSaving]             = useState(false);
  const [loading, setLoading]           = useState(true);
  const [oauthStatus, setOauthStatus]   = useState({ meta: { configured:false }, linkedin: { configured:false } });
  const [showDocs, setShowDocs]         = useState({});
  const [toast, setToast]               = useState({ msg:'', type:'info' });
  // Meta account picker (multiple ad accounts)
  const [metaAccounts, setMetaAccounts] = useState(null);
  const [metaToken, setMetaToken]       = useState('');
  const [metaUser, setMetaUser]         = useState('');

  const showToast = (msg, type='info') => {
    setToast({ msg, type });
    setTimeout(() => setToast({ msg:'', type:'info' }), 6000);
  };

  // Handle OAuth callback params
  useEffect(() => {
    const success = searchParams.get('success');
    const error   = searchParams.get('error');
    const accounts = searchParams.get('meta_accounts');
    const token    = searchParams.get('meta_token');
    const user     = searchParams.get('meta_user');

    if (success) {
      const account = searchParams.get('account');
      showToast(`✅ ${success === 'meta' ? 'Meta' : 'LinkedIn'} connected successfully${account ? ` — ${account}` : ''}!`, 'success');
      setSearchParams({});
      fetchConnections();
    }

    if (error) {
      const msg = decodeURIComponent(error.replace(/^(meta_|linkedin_)/, ''));
      showToast(`❌ ${msg}`, 'error');
      setSearchParams({});
    }

    // Meta account picker
    if (accounts && token) {
      try {
        setMetaAccounts(JSON.parse(decodeURIComponent(accounts)));
        setMetaToken(decodeURIComponent(token));
        setMetaUser(decodeURIComponent(user || ''));
        setSearchParams({});
      } catch {}
    }
  }, [searchParams]);

  const fetchConnections = async () => {
    try {
      const res = await integrationsAPI.getAll();
      const map = {};
      (res.data || []).forEach(c => { map[c.platform] = c; });
      setConnections(map);
    } catch {}
  };

  useEffect(() => {
    fetchConnections().finally(() => setLoading(false));
    // Check which OAuth providers are configured
    api.get('/oauth/status').then(res => setOauthStatus(res.data)).catch(() => {});
  }, []);

  // ── OAuth login handler ──────────────────────────────────────────────────
  const handleOAuthConnect = (platformId) => {
    const adAccountId = credentials[platformId]?.adAccountId || '';
    const url = `${SERVER_URL}/api/oauth/${platformId}/authorize?adAccountId=${adAccountId}`;
    // Open OAuth flow — redirects back to /connect with success/error params
    window.location.href = url;
  };

  // ── Select Meta ad account (from picker) ─────────────────────────────────
  const handleSelectMetaAccount = async (account) => {
    try {
      setSaving(true);
      await api.post('/integrations/meta/connect', {
        accessToken: metaToken,
        adAccountId: account.id
      });
      setMetaAccounts(null);
      setMetaToken('');
      fetchConnections();
      showToast(`✅ Meta connected — ${account.name}`, 'success');
    } catch (err) {
      showToast('❌ ' + (err.response?.data?.message || err.message), 'error');
    } finally { setSaving(false); }
  };

  // ── Manual connect ────────────────────────────────────────────────────────
  const handleManualConnect = async (platformId) => {
    const creds = credentials[platformId] || {};
    const info  = PLATFORM_FIELDS[platformId];
    const missing = (info?.fields || []).filter(f => f.required && !creds[f.key]?.trim());
    if (missing.length > 0) {
      showToast(`❌ Please fill in: ${missing.map(f => f.label).join(', ')}`, 'error');
      return;
    }
    setSaving(true);
    try {
      const res = await integrationsAPI.connect(platformId, creds);
      setConnections(c => ({ ...c, [platformId]: { platform:platformId, status:'connected', hasToken:true, accountName:res.data.account?.accountName, lastSync:null } }));
      setConnecting(null);
      setCredentials(c => ({ ...c, [platformId]: {} }));
      showToast(`✅ ${PLATFORM_FIELDS[platformId]?.label} connected!`, 'success');
    } catch (err) {
      showToast(`❌ ${err.response?.data?.message || err.message}`, 'error');
    } finally { setSaving(false); }
  };

  const handleDisconnect = async (platformId) => {
    if (!window.confirm(`Disconnect ${PLATFORM_FIELDS[platformId]?.label}?`)) return;
    try {
      await integrationsAPI.disconnect(platformId);
      setConnections(c => { const n = {...c}; delete n[platformId]; return n; });
      showToast(`Disconnected ${PLATFORM_FIELDS[platformId]?.label}`);
    } catch (err) { showToast('❌ ' + err.message, 'error'); }
  };

  const handleSync = async (platformId) => {
    setSyncing(platformId);
    try {
      const res = await integrationsAPI.sync(platformId);
      showToast(`✅ ${res.data.message}`, 'success');
      setConnections(c => ({ ...c, [platformId]: { ...c[platformId], lastSync: new Date().toISOString() } }));
    } catch (err) {
      showToast(`❌ ${err.response?.data?.message || err.message}`, 'error');
    } finally { setSyncing(null); }
  };

  const checkPermissions = async (platformId) => {
    setCheckingPerms(platformId);
    try {
      const res = await integrationsAPI.checkPermissions(platformId);
      setPermResults(r => ({ ...r, [platformId]: res.data }));
    } catch (err) { showToast('❌ ' + err.message, 'error'); }
    finally { setCheckingPerms(null); }
  };

  const toastStyles = {
    success: { bg:'rgba(22,163,74,0.12)',  border:'rgba(22,163,74,0.3)'  },
    error:   { bg:'rgba(239,68,68,0.12)',  border:'rgba(239,68,68,0.3)'  },
    info:    { bg:'rgba(37,99,235,0.1)',   border:'rgba(37,99,235,0.25)' },
  };

  return (
    <Layout>
      {/* Toast */}
      {toast.msg && (
        <div style={{ position:'fixed', top:20, right:20, zIndex:9999, maxWidth:460, padding:'14px 18px', borderRadius:12, background:toastStyles[toast.type]?.bg, border:`1px solid ${toastStyles[toast.type]?.border}`, boxShadow:'0 8px 32px rgba(0,0,0,0.2)', fontSize:13, color:'var(--text-primary)', animation:'slideIn 0.3s ease-out', display:'flex', gap:10, alignItems:'flex-start' }}>
          <span style={{ flex:1, lineHeight:1.5 }}>{toast.msg}</span>
          <button onClick={() => setToast({msg:'',type:'info'})} style={{ background:'none', border:'none', color:'var(--text-faint)', cursor:'pointer', fontSize:18, padding:0 }}>✕</button>
        </div>
      )}

      <div className="page-header">
        <div>
          <h1 className="page-title">Platform Integrations</h1>
          <p className="page-subtitle">Connect your ad accounts — credentials are saved securely</p>
        </div>
      </div>

      {/* How it works */}
      <div style={{ padding:'16px 20px', borderRadius:12, background:'rgba(124,58,237,0.07)', border:'1px solid rgba(124,58,237,0.18)', marginBottom:28, display:'flex', gap:14 }}>
        <span style={{ fontSize:22, flexShrink:0 }}>🔐</span>
        <div style={{ fontSize:13, color:'var(--text-muted)', lineHeight:1.7, flex:1 }}>
          <strong style={{ color:'var(--text-primary)' }}>How it works:</strong> For Meta and LinkedIn, click the OAuth button for one-click login — no manual token copying needed.
          Credentials are saved encrypted to your account and persist across sessions. Auto-syncs every hour.
        </div>
      </div>

      {/* Meta account picker modal */}
      {metaAccounts && (
        <div style={{ position:'fixed', inset:0, background:'rgba(0,0,0,0.65)', zIndex:2000, display:'flex', alignItems:'center', justifyContent:'center', padding:20 }}>
          <div className="glass-card" style={{ padding:32, maxWidth:460, width:'100%' }}>
            <h3 style={{ fontSize:18, fontWeight:800, color:'var(--text-primary)', margin:'0 0 8px' }}>
              Select Ad Account
            </h3>
            <p style={{ fontSize:13, color:'var(--text-muted)', margin:'0 0 20px' }}>
              Multiple ad accounts found for <strong>{metaUser}</strong>. Select which one to connect:
            </p>
            <div style={{ display:'flex', flexDirection:'column', gap:10 }}>
              {metaAccounts.map(account => (
                <button key={account.id} onClick={() => handleSelectMetaAccount(account)} disabled={saving}
                  style={{ padding:'14px 18px', borderRadius:12, border:'1px solid var(--border-subtle)', background:'var(--bg-elevated)', cursor:'pointer', textAlign:'left', transition:'all 0.2s', fontFamily:'DM Sans,sans-serif' }}
                  onMouseEnter={e => e.currentTarget.style.borderColor='var(--purple-primary)'}
                  onMouseLeave={e => e.currentTarget.style.borderColor='var(--border-subtle)'}
                >
                  <div style={{ fontSize:14, fontWeight:700, color:'var(--text-primary)', marginBottom:3 }}>{account.name}</div>
                  <div style={{ fontSize:12, color:'var(--text-faint)', fontFamily:'DM Mono,monospace' }}>{account.id}</div>
                </button>
              ))}
            </div>
            <button className="btn-secondary" onClick={() => { setMetaAccounts(null); setMetaToken(''); }} style={{ width:'100%', justifyContent:'center', marginTop:16 }}>
              Cancel
            </button>
          </div>
        </div>
      )}

      {loading ? (
        <div style={{ display:'flex', flexDirection:'column', gap:14 }}>
          {PLATFORMS.map(p => <div key={p.id} className="skeleton" style={{ height:100, borderRadius:16 }}/>)}
        </div>
      ) : (
        <div style={{ display:'flex', flexDirection:'column', gap:14 }}>
          {PLATFORMS.map(pl => {
            const Icon   = PlatformIcons[pl.id];
            const info   = PLATFORM_FIELDS[pl.id];
            const conn   = connections[pl.id];
            const isConn = conn?.status === 'connected';
            const isErr  = conn?.status === 'error';
            const isOpen = connecting === pl.id;
            const isSyncing = syncing === pl.id;
            const hasOAuth  = info?.oauthSupported && oauthStatus[pl.id]?.configured;

            return (
              <div key={pl.id} className="glass-card" style={{
                padding:22,
                border:`1px solid ${isConn ? pl.color+'55' : isErr ? 'rgba(239,68,68,0.35)' : 'var(--border-subtle)'}`,
                background: isConn ? `${pl.color}07` : 'var(--bg-card)',
                transition:'all 0.2s'
              }}>
                {/* Header */}
                <div style={{ display:'flex', justifyContent:'space-between', alignItems:'flex-start', flexWrap:'wrap', gap:12 }}>
                  <div style={{ display:'flex', alignItems:'center', gap:12 }}>
                    {Icon && <Icon size={28}/>}
                    <div>
                      <div style={{ fontWeight:700, fontSize:15, color:'var(--text-primary)' }}>{pl.name}</div>
                      {isConn ? (
                        <div style={{ fontSize:12, color:'#16a34a', fontWeight:600 }}>
                          ● Connected{conn.accountName ? ` · ${conn.accountName}` : ''}
                        </div>
                      ) : isErr ? (
                        <div style={{ fontSize:12, color:'#ef4444', fontWeight:600 }}>● Error</div>
                      ) : (
                        <div style={{ fontSize:12, color:'var(--text-faint)' }}>Not connected</div>
                      )}
                    </div>
                  </div>

                  <div style={{ display:'flex', gap:8, flexWrap:'wrap', alignItems:'center' }}>
                    {isConn && conn.lastSync && (
                      <div style={{ fontSize:11, color:'var(--text-faint)' }}>
                        Synced {new Date(conn.lastSync).toLocaleString()}
                      </div>
                    )}

                    {isConn ? (
                      <>
                        <button className="btn-primary" onClick={() => handleSync(pl.id)} disabled={isSyncing} style={{ fontSize:12, padding:'7px 14px' }}>
                          {isSyncing ? '⏳ Syncing...' : '🔄 Sync Data'}
                        </button>
                        <button className="btn-secondary" onClick={() => checkPermissions(pl.id)} disabled={checkingPerms === pl.id} style={{ fontSize:12, padding:'7px 12px' }}>
                          {checkingPerms === pl.id ? '🔍...' : '🔍 Check'}
                        </button>
                        <button className="btn-secondary" onClick={() => setConnecting(isOpen ? null : pl.id)} style={{ fontSize:12, padding:'7px 12px' }}>
                          ⚙️ Update
                        </button>
                        <button onClick={() => handleDisconnect(pl.id)} style={{ padding:'7px 10px', borderRadius:8, border:'1px solid rgba(239,68,68,0.3)', background:'rgba(239,68,68,0.08)', color:'#ef4444', cursor:'pointer', fontSize:12, fontWeight:600 }}>
                          ✕
                        </button>
                      </>
                    ) : (
                      <>
                        {/* OAuth button */}
                        {info?.oauthSupported && (
                          hasOAuth ? (
                            <button
                              onClick={() => handleOAuthConnect(pl.id)}
                              style={{
                                padding:'8px 18px', borderRadius:9, border:'none',
                                background: info.oauthColor, color:'white',
                                cursor:'pointer', fontSize:13, fontWeight:700,
                                fontFamily:'DM Sans,sans-serif',
                                display:'flex', alignItems:'center', gap:8,
                                boxShadow:'0 2px 8px rgba(0,0,0,0.2)'
                              }}
                            >
                              {info.oauthIcon} {info.oauthLabel}
                            </button>
                          ) : (
                            <div style={{ fontSize:11, color:'var(--text-faint)', padding:'6px 10px', borderRadius:8, background:'var(--bg-elevated)', border:'1px solid var(--border-subtle)' }}>
                              ⚙️ Add {pl.id.toUpperCase()}_APP_ID to .env for OAuth
                            </div>
                          )
                        )}
                        {/* Manual connect button */}
                        <button className={info?.oauthSupported ? 'btn-secondary' : 'btn-primary'} onClick={() => setConnecting(isOpen ? null : pl.id)} style={{ fontSize:12, padding:'8px 14px' }}>
                          {isOpen ? '✕ Cancel' : info?.oauthSupported ? '🔑 Manual' : '🔗 Connect'}
                        </button>
                        {info?.docs && (
                          <a href={info.docs} target="_blank" rel="noopener noreferrer"
                            style={{ padding:'8px 10px', borderRadius:8, border:'1px solid var(--border-subtle)', color:'var(--text-muted)', fontSize:12, display:'flex', alignItems:'center', textDecoration:'none' }}
                            title="API Documentation">📖</a>
                        )}
                      </>
                    )}
                  </div>
                </div>

                {/* Permission check results */}
                {permResults[pl.id] && (
                  <div style={{ marginTop:14, padding:'14px 16px', borderRadius:10, background:'var(--bg-elevated)', border:'1px solid var(--border-subtle)' }}>
                    <div style={{ fontSize:12, fontWeight:700, color:'var(--text-primary)', marginBottom:10 }}>🔍 Permission Check</div>
                    <div style={{ display:'flex', flexDirection:'column', gap:6 }}>
                      {[
                        { label:'Token Valid',       ok: permResults[pl.id].tokenValid,        value: permResults[pl.id].userName },
                        { label:'ads_read',          ok: permResults[pl.id].permissions?.includes('ads_read') },
                        { label:'ads_management',    ok: permResults[pl.id].permissions?.includes('ads_management') },
                        { label:'Can Read Campaigns',ok: permResults[pl.id].canReadCampaigns,   err: permResults[pl.id].campaignError },
                      ].map(item => (
                        <div key={item.label} style={{ display:'flex', alignItems:'center', gap:10, fontSize:12 }}>
                          <span>{item.ok ? '✅' : '❌'}</span>
                          <span style={{ fontWeight:600, color:'var(--text-primary)', minWidth:140 }}>{item.label}</span>
                          {item.value && <span style={{ color:'var(--text-muted)' }}>{item.value}</span>}
                          {!item.ok && item.err && <span style={{ color:'#ef4444', fontSize:11 }}>{item.err.slice(0, 80)}</span>}
                        </div>
                      ))}
                    </div>
                    {permResults[pl.id].missingPermissions?.length > 0 && (
                      <div style={{ marginTop:10, padding:'8px 12px', borderRadius:8, background:'rgba(239,68,68,0.1)', border:'1px solid rgba(239,68,68,0.25)', fontSize:12, color:'#ef4444' }}>
                        ⚠️ Missing: <strong>{permResults[pl.id].missingPermissions.join(', ')}</strong> — reconnect via OAuth to fix.
                      </div>
                    )}
                    {permResults[pl.id].canReadCampaigns && (
                      <div style={{ marginTop:10, padding:'8px 12px', borderRadius:8, background:'rgba(22,163,74,0.1)', border:'1px solid rgba(22,163,74,0.25)', fontSize:12, color:'#16a34a' }}>
                        ✅ All good! Click Sync Data to import campaigns.
                      </div>
                    )}
                    <button onClick={() => setPermResults(r => ({ ...r, [pl.id]: null }))} style={{ marginTop:8, background:'none', border:'none', color:'var(--text-faint)', fontSize:11, cursor:'pointer' }}>
                      Dismiss
                    </button>
                  </div>
                )}

                {/* Manual connect form */}
                {isOpen && (
                  <div style={{ marginTop:18, paddingTop:18, borderTop:'1px solid var(--border-subtle)', animation:'fadeIn 0.2s ease-out' }}>
                    {/* Instructions */}
                    <div style={{ marginBottom:16 }}>
                      <button onClick={() => setShowDocs(d => ({ ...d, [pl.id]: !d[pl.id] }))}
                        style={{ background:'none', border:'none', color:'var(--purple-light)', fontSize:13, fontWeight:600, cursor:'pointer', padding:0, marginBottom:8, display:'flex', alignItems:'center', gap:6 }}>
                        {showDocs[pl.id] ? '▼' : '▶'} How to get credentials
                      </button>
                      {showDocs[pl.id] && (
                        <div style={{ background:'var(--bg-elevated)', borderRadius:10, padding:'14px 16px' }}>
                          {(info?.instructions || []).map(s => (
                            <div key={s.step} style={{ display:'flex', gap:12, marginBottom:10, alignItems:'flex-start' }}>
                              <div style={{ width:22, height:22, borderRadius:'50%', background:'rgba(124,58,237,0.2)', display:'flex', alignItems:'center', justifyContent:'center', fontSize:11, fontWeight:800, color:'var(--purple-light)', flexShrink:0 }}>
                                {s.step}
                              </div>
                              <div style={{ fontSize:13, color:'var(--text-muted)', lineHeight:1.5 }}>{s.text}</div>
                            </div>
                          ))}
                          {info?.tip && (
                            <div style={{ marginTop:8, padding:'8px 12px', borderRadius:8, background:'rgba(245,158,11,0.1)', border:'1px solid rgba(245,158,11,0.25)', fontSize:12, color:'#d97706' }}>
                              💡 {info.tip}
                            </div>
                          )}
                        </div>
                      )}
                    </div>

                    {/* Fields */}
                    <div style={{ display:'grid', gridTemplateColumns:'repeat(auto-fill,minmax(260px,1fr))', gap:12 }}>
                      {(info?.fields || []).map(field => (
                        <div key={field.key}>
                          <label className="form-label">
                            {field.label}
                            {field.required && <span style={{ color:'#ef4444', marginLeft:4 }}>*</span>}
                          </label>
                          <input className="form-input" type={field.type || 'text'} placeholder={field.placeholder}
                            value={credentials[pl.id]?.[field.key] || ''}
                            onChange={e => setCredentials(c => ({ ...c, [pl.id]: { ...c[pl.id], [field.key]: e.target.value } }))}
                            style={{ fontSize:13 }} autoComplete="off" spellCheck={false}/>
                        </div>
                      ))}
                    </div>

                    <div style={{ display:'flex', gap:10, marginTop:16 }}>
                      <button className="btn-secondary" onClick={() => setConnecting(null)} style={{ fontSize:13 }}>Cancel</button>
                      <button className="btn-primary" onClick={() => handleManualConnect(pl.id)} disabled={saving} style={{ fontSize:13 }}>
                        {saving ? '⏳ Connecting...' : `✓ Save & Connect ${pl.name}`}
                      </button>
                    </div>
                  </div>
                )}
              </div>
            );
          })}
        </div>
      )}
    </Layout>
  );
}
